noncompliant:
// Noncompliant: volatile on function return type
volatile int getValue() {
  return 42;
}

// Noncompliant: volatile on function parameter
void processValue(volatile int param) {
  // ...
}

// Noncompliant: volatile on structured binding
auto [volatile x, y] = std::make_pair(1, 2);

compliant:
// Compliant: volatile on global variable
volatile int globalCounter = 0;

// Compliant: volatile on local variable
void function() {
  volatile int localFlag = 1;
  // ...
}

// Compliant: volatile on struct member
struct Device {
  volatile int status;
  int data;
};
